content.text:
Try-catch bloku aşağıdakı kimi yazılır:
try {
  // Potensial səhv yarada biləcək kod
}
catch (exception_type variable) {
  // İstisnanın idarə edilməsi
}
`exception_type` istisnanın tipini (məsələn, `std::exception`, `int`, `std::string`) göstərir, `variable` isə istisnanın məzmununu saxlayır.

content.code:
#include <iostream>
#include <stdexcept>

int main() {
  try {
    int number = 10;
    if(number == 10) {
      throw "Error: Number is 10";
    }
    std::cout << "No error occurred\n";
  } catch(const char* msg) {
    std::cout << "Caught: " << msg << std::endl;
  }
  return 0;
}
// Output:
// Caught: Error: Number is 10

#include <iostream>
#include <stdexcept>

int main() {
  try {
    int divisor = 0;
    if(divisor == 0) {
      throw std::runtime_error("Division by zero!");
    }
    int result = 10 / divisor;
  } catch(const std::runtime_error& e) {
    std::cout << "Caught: " << e.what() << std::endl;
  }
  return 0;
}
// Output:
// Caught: Division by zero!

#include <iostream>
#include <stdexcept>

int main() {
  try {
    int value = -1;
    if(value < 0) {
      throw std::invalid_argument("Negative value!");
    }
    if(value == 0) {
      throw std::runtime_error("Zero value!");
    }
  } catch(const std::invalid_argument& e) {
    std::cout << "Invalid argument: " << e.what() << std::endl;
  } catch(const std::runtime_error& e) {
    std::cout << "Runtime error: " << e.what() << std::endl;
  } catch(...) {
    std::cout << "Unknown error\n";
  }
  return 0;
}
// Output:
// Invalid argument: Negative value!

#include <iostream>
#include <stdexcept>
#include <string>

class CustomError : public std::exception {
public:
  const char* what() const noexcept override {
    return "Custom error occurred!";
  }
};

int main() {
  try {
    throw CustomError();
  } catch(const std::exception& e) {
    std::cout << "Caught: " << e.what() << std::endl;
  }
  return 0;
}
// Output:
// Caught: Custom error occurred!

